class BadRequestError extends Error {
  constructor(message) {
    super(message);
    this.name = 'BadRequestError';
    this.status = 400;
  }
}

class NotFoundError extends Error {
  constructor(message) {
    super(message);
    this.name = 'NotFoundError';
    this.status = 404;
  }
}

function sendError(res, status, code, message) {
  res.status(status).json({ error: { code, message } });
}
exports.sendError = sendError;

const express = require('express');
const router = express.Router({ mergeParams: true });
const commentsService = require('./service');

router.post('/', async (req, res) => {
  const { message } = req.body;
  if (!message) return sendError(res, 400, 'MissingMessage', 'Message is required');
  const comment = await commentsService.createComment(req.params.projectId, req.params.taskId, message);
  res.status(201).json({ comment });
});

router.get('/', async (req, res) => {
  const comments = await commentsService.getComments(req.params.projectId, req.params.taskId);
  res.json({ comments });
});

module.exports = router;

const { sendError } = require('../../lib/errors');
const { randomUUID } = require('node:crypto');

let commentsStore = [];

function getComments(projectId, taskId) {
  return commentsStore.filter(comment => comment.projectId === projectId && comment.taskId === taskId);
}

async function createComment(projectId, taskId, message) {
  const newComment = { id: randomUUID(), projectId, taskId, message };
  commentsStore.push(newComment);
  return newComment;
}

exports.getComments = getComments;
exports.createComment = createComment;

