const express = require('express');
const router = express.Router({ mergeParams: true });
const tasksService = require('./service');

router.post('/', async (req, res) => {
  const { title, description } = req.body;
  if (!title || !description) return sendError(res, 400, 'MissingFields', 'Title and description are required');
  const task = await tasksService.createTask(req.params.projectId, title, description);
  res.status(201).json({ task });
});

router.get('/', async (req, res) => {
  const { status } = req.query;
  let tasks;
  if (status) {
    tasks = await tasksService.filterTasksByStatus(req.params.projectId, status);
  } else {
    tasks = await tasksService.getAllTasks(req.params.projectId);
  }
  res.json({ tasks });
});

router.patch('/:taskId', async (req, res) => {
  const { taskId } = req.params;
  const { status } = req.body;
  if (!status || !['todo', 'done'].includes(status)) return sendError(res, 400, 'InvalidStatus', 'Task status must be todo or done');
  const updatedTask = await tasksService.updateTaskStatus(req.params.projectId, taskId, status);
  res.json({ task: updatedTask });
});

module.exports = router;

const { sendError } = require('../../lib/errors');
const { randomUUID } = require('node:crypto');

let tasksStore = [];

function getAllTasks(projectId) {
  return tasksStore.filter(task => task.projectId === projectId);
}

function filterTasksByStatus(projectId, status) {
  return tasksStore.filter(task => task.projectId === projectId && task.status === status);
}

async function createTask(projectId, title, description) {
  const newTask = { id: randomUUID(), projectId, title, description, status: 'todo' };
  tasksStore.push(newTask);
  return newTask;
}

async function updateTaskStatus(projectId, taskId, status) {
  const taskIndex = tasksStore.findIndex(task => task.id === taskId && task.projectId === projectId);
  if (taskIndex === -1) return sendError(res, 404, 'TaskNotFound', 'Task not found');
  tasksStore[taskIndex].status = status;
  return tasksStore[taskIndex];
}

exports.getAllTasks = getAllTasks;
exports.filterTasksByStatus = filterTasksByStatus;
exports.createTask = createTask;
exports.updateTaskStatus = updateTaskStatus;

const app = require('./app');
const port = process.env.PORT || 3000;

module.exports = app;
